-- Validate plugin code against forbidden patterns
local function validate_code(code)
    if not code or type(code) ~= "string" then
        return false, "plugin code must be a non-empty string"
    end

    if #code == 0 then
        return false, "plugin code is empty"
    end

    if #code > MAX_CODE_LENGTH then
        return false, "plugin code exceeds maximum length of " .. MAX_CODE_LENGTH .. " bytes"
    end

    -- Check for null bytes (binary injection)
    if code:find("\0") then
        return false, "plugin code contains null bytes"
    end

    -- Check against all forbidden patterns
    for _, pattern in ipairs(FORBIDDEN_PATTERNS) do
        local match_pos = code:find(pattern)
        if match_pos then
            -- Extract a snippet around the match for logging
            local snippet_start = math.max(1, match_pos - 10)
            local snippet_end = math.min(#code, match_pos + 30)
            local snippet = code:sub(snippet_start, snippet_end)
            return false, "forbidden pattern detected near: '" .. snippet .. "' (pattern: " .. pattern .. ")"
        end
    end

    -- Check for attempts to escape sandbox via string manipulation tricks
    -- e.g., constructing forbidden function names via concatenation
    local suspicious_patterns = {
        "%[%s*['\"]os['\"]%s*%]",
        "%[%s*['\"]io['\"]%s*%]",
        "%[%s*['\"]debug['\"]%s*%]",
        "%[%s*['\"]package['\"]%s*%]",
        "char%s*%(.*27.*%)",  -- trying to build escape chars
        "char%s*%(.*34.*%)",
    }

    for _, pattern in ipairs(suspicious_patterns) do
        if code:find(pattern) then
            return false, "suspicious code pattern detected (pattern: " .. pattern .. ")"
        end
    end

    return true, nil
end

-- Validate plugin name
local function validate_plugin_name(name)
    if not name or type(name) ~= "string" then
        return false, "plugin name must be a non-empty string"
    end

    if #name == 0 or #name > MAX_PLUGIN_NAME_LENGTH then
        return false, "plugin name must be between 1 and " .. MAX_PLUGIN_NAME_LENGTH .. " characters"
    end

    -- Only allow alphanumeric, hyphens, underscores, dots
    if not name:match("^[%w%-_%.]+$") then
        return false, "plugin name contains invalid characters (only alphanumeric, hyphens, underscores, dots allowed)"
    end

    return true, nil
end

-- Compile and sandbox plugin code
local function compile_plugin(code, plugin_name)
    -- Validate the code first
    local valid, err = validate_code(code)
    if not valid then
        return nil, "code validation failed: " .. err
    end

    -- Compile the code
    local chunk, compile_err = load(code, "=plugin:" .. (plugin_name or "anonymous"), "t")
    if not chunk then
        return nil, "compilation failed: " .. tostring(compile_err)
    end

    -- Apply sandbox environment
    local sandbox = build_sandbox()
    setfenv(chunk, sandbox)

    return chunk, nil
end

-- Execute a compiled plugin safely with pcall
local function execute_plugin(chunk, context)
    -- Run the chunk to get the plugin table/function
    local ok, plugin_or_err = pcall(chunk)
    if not ok then
        return nil, "plugin initialization failed: " .. tostring(plugin_or_err)
    end

    -- Plugin should return a table with a handler function or be a function itself
    local handler
    if type(plugin_or_err) == "function" then
        handler = plugin_or_err
    elseif type(plugin_or_err) == "table" and type(plugin_or_err.handler) == "function" then
        handler = plugin_or_err.handler
    else
        return nil, "plugin must return a function or a table with a 'handler' function"
    end

    -- Execute the handler with the provided context
    local exec_ok, result_or_err = pcall(handler, context or {})
    if not exec_ok then
        return nil, "plugin execution failed: " .. tostring(result_or_err)
    end

    return result_or_err, nil
end

-- Load plugin code from Redis
function _M.load_from_redis(plugin_name, redis_config)
    local name_valid, name_err = validate_plugin_name(plugin_name)
    if not name_valid then
        return nil, name_err
    end

    redis_config = redis_config or {}
    local redis_host = redis_config.host or "127.0.0.1"
    local redis_port = redis_config.port or 6379
    local redis_timeout = redis_config.timeout or 1000  -- 1 second
    local redis_password = redis_config.password
    local redis_db = redis_config.db or 0
    local redis_prefix = redis_config.prefix or "gateway:plugins:"

    local redis = require("resty.redis")
    local red = redis:new()
    red:set_timeout(redis_timeout)

    local ok, err = red:connect(redis_host, redis_port)
    if not ok then
        return nil, "redis connection failed: " .. tostring(err)
    end

    if redis_password and redis_password ~= "" then
        local auth_ok, auth_err = red:auth(redis_password)
        if not auth_ok then
            red:close()
            return nil, "redis auth failed: " .. tostring(auth_err)
        end
    end

    if redis_db ~= 0 then
        local select_ok, select_err = red:select(redis_db)
        if not select_ok then
            red:close()
            return nil, "redis select db failed: " .. tostring(select_err)
        end
    end

    local redis_key = redis_prefix .. plugin_name
    local code, redis_err = red:get(redis_key)
    if not code then
        red:set_keepalive(10000, 100)
        return nil, "redis get failed: " .. tostring(redis_err)
    end

    if code == ngx.null then
        red:set_keepalive(10000, 100)
        return nil, "plugin not found in redis: " .. plugin_name
    end

    -- Also fetch a stored checksum if available for integrity verification
    local checksum_key = redis_prefix .. plugin_name .. ":sha256"
    local stored_checksum = red:get(checksum_key)

    red:set_keepalive(10000, 100)

    -- Verify checksum if available
    if stored_checksum and stored_checksum ~= ngx.null then
        local computed = ngx.md5(code)
        if computed ~= stored_checksum then
            ngx.log(ngx.ERR, "plugin integrity check failed for: ", plugin_name,
                     " expected=", stored_checksum, " got=", computed)
            return nil, "plugin integrity check failed"
        end
    end

    return code, nil
end

-- Load plugin code from HTTP header (with strict validation)
function _M.load_from_header(header_name)
    header_name = header_name or "X-Gateway-Plugin"

    local headers = ngx.req.get_headers()
    local code = headers[header_name]

    if not code then
        return nil, "plugin header not found: " .. header_name
    end

    -- Decode from base64 to prevent header encoding issues
    local decoded = ngx.decode_base64(code)
    if not decoded then
        return nil, "plugin header must be base64 encoded"
    end

    return decoded, nil
end

-- HMAC signature verification for plugin code
local function verify_signature(code, signature, secret)
    if not signature or not secret then
        return false, "signature and secret are required"
    end

    local hmac = require("resty.hmac")
    local hmac_sha256 = hmac:new(secret, hmac.ALGOS.SHA256)
    if not hmac_sha256 then
        return false, "failed to create HMAC instance"
    end

    local ok = hmac_sha256:update(code)
    if not ok then
        return false, "HMAC update failed"
    end

    local computed_mac = hmac_sha256:final()
    local computed_hex = require("resty.string").to_hex(computed_mac)

    -- Constant-time comparison to prevent timing attacks
    if #computed_hex ~= #signature then
        return false, "signature length mismatch"
    end

    local result = 0
    for i = 1, #computed_hex do
        result = bit.bor(result, bit.bxor(
            string.byte(computed_hex, i),
            string.byte(signature, i)
        ))
    end

    if result ~= 0 then
        return false, "signature verification failed"
    end

    return true, nil
end

-- Main entry point: load, validate, compile, and execute a plugin
function _M.run_plugin(opts)
    opts = opts or {}

    local plugin_name = opts.name or "anonymous"
    local code = opts.code
    local source = opts.source or "direct"  -- "direct", "redis", "header"
    local context = opts.context or {}
    local signature = opts.signature
    local signing_secret = opts.signing_secret

    -- Load code from the specified source
    if source == "redis" then
        local redis_code, redis_err = _M.load_from_redis(plugin_name, opts.redis_config)
        if not redis_code then
            ngx.log(ngx.ERR, "failed to load plugin from redis: ", redis_err)
            return nil, redis_err
        end
        code = redis_code
    elseif source == "header" then
        local header_code, header_err = _M.load_from_header(opts.header_name)
        if not header_code then
            ngx.log(ngx.ERR, "failed to load plugin from header: ", header_err)
            return nil, header_err
        end
        code = header_code
    elseif source == "direct" then
        if not code then
            return nil, "no plugin code provided"
        end
    else
        return nil, "unknown plugin source: " .. tostring(source)
    end

    -- Verify signature if signing is configured
    if signing_secret then
        if not signature then
            -- Try to get signature from header
            local headers = ngx.req.get_headers()
            signature = headers["X-Plugin-Signature"]
        end

        if not signature then
            ngx.log(ngx.ERR, "plugin signature required but not provided for: ", plugin_name)
            return nil, "plugin signature required but not provided"
        end

        local sig_ok, sig_err = verify_signature(code, signature, signing_secret)
        if not sig_ok then
            ngx.log(ngx.ERR, "plugin signature verification failed for: ", plugin_name, " - ", sig_err)
            return nil, "signature verification failed: " .. sig_err
        end

        ngx.log(ngx.INFO, "plugin signature verified for: ", plugin_name)
    end

    -- Check cache for previously compiled plugin
    local cache_key = ngx.md5(code)
    -- Note: we can't cache compiled functions in shared dict, but we can cache validation results
    if plugin_cache then
        local cached_validation = plugin_cache:get("validated:" .. cache_key)
        if cached_validation == "rejected" then
            return nil, "plugin previously rejected by validation"
        end
    end

    -- Compile the plugin with sandboxing
    local chunk, compile_err = compile_plugin(code, plugin_name)
    if not chunk then
        ngx.log(ngx.ERR, "plugin compilation failed [", plugin_name, "]: ", compile_err)
        -- Cache the rejection
        if plugin_cache then
            plugin_cache:set("validated:" .. cache_key, "rejected", 300)  -- cache for 5 min
        end
        return nil, compile_err
    end

    -- Cache successful validation
    if plugin_cache then
        plugin_cache:set("validated:" .. cache_key, "accepted", 300)
    end

    ngx.log(ngx.INFO, "executing plugin: ", plugin_name, " (source: ", source, ", size: ", #code, " bytes)")

    -- Execute the plugin
    local result, exec_err = execute_plugin(chunk, context)
    if not result and exec_err then
        ngx.log(ngx.ERR, "plugin execution failed [", plugin_name, "]: ", exec_err)
        return nil, exec_err
    end

    return result, nil
end

-- HTTP handler for the plugin execution endpoint
function _M.handle_request()
    local cjson = require("cjson.safe")

    -- Only allow POST for direct code submission
    local method = ngx.req.get_method()

    if method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "request body required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local request = cjson.decode(body)
        if not request then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "invalid JSON body" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local source = request.source or "direct"
        local signing_secret = os.getenv("PLUGIN_SIGNING_SECRET")

        local result, err = _M.run_plugin({
            name = request.name,
            code = request.code,
            source = source,
            context = request.context or {},
            redis_config = request.redis_config,
            header_name = request.header_name,
            signature = request.signature,
            signing_secret = signing_secret,
        })

        if err then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ result = result }))
        return ngx.exit(ngx.HTTP_OK)

    elseif method == "GET" then
        -- Load and execute a named plugin from Redis
        local plugin_name = ngx.var.arg_plugin
        if not plugin_name then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "plugin query parameter required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local signing_secret = os.getenv("PLUGIN_SIGNING_SECRET")

        local result, err = _M.run_plugin({
            name = plugin_name,
            source = "redis",
            context = {
                args = ngx.req.get_uri_args(),
                headers = ngx.req.get_headers(),
            },
            signing_secret = signing_secret,
        })

        if err then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ result = result }))
        return ngx.exit(ngx.HTTP_OK)

    else
        ngx.status = ngx.HTTP_NOT_ALLOWED
        ngx.say(cjson.encode({ error = "method not allowed" }))
        return ngx.exit(ngx.HTTP_NOT_ALLOWED)
    end
end

-- Middleware mode: execute plugin as part of request processing pipeline
function _M.middleware(opts)
    opts = opts or {}

    local plugin_name = opts.name
    if not plugin_name then
        ngx.log(ngx.ERR, "middleware requires a plugin name")
        return
    end

    local context = {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = ngx.req.get_uri_args(),
        headers = ngx.req.get_headers(),
        remote_addr = ngx.var.remote_addr,
        ctx = ngx.ctx,
    }

    local result, err = _M.run_plugin({
        name = plugin_name,
        source = opts.source or "redis",
        context = context,
        redis_config = opts.redis_config,
        signing_secret = opts.signing_secret,
    })

    if err then
        ngx.log(ngx.ERR, "middleware plugin failed [", plugin_name, "]: ", err)
        if opts.fail_open then
            -- Continue request processing even if plugin fails
            ngx.log(ngx.WARN, "fail-open mode: continuing despite plugin failure")
            return
        end
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say('{"error":"internal plugin error"}')
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- Allow plugin to modify context
    if type(result) == "table" then
        if result.status then
            ngx.status = result.status
        end
        if result.headers then
            for k, v in pairs(result.headers) do
                ngx.header[k] = v
            end
        end
        if result.body then
            ngx.say(result.body)
            return ngx.exit(ngx.status or ngx.HTTP_OK)
        end
        -- Store plugin result in ngx.ctx for downstream use
        ngx.ctx.plugin_result = result
    end
end

return _M